//! GTEx Portal API v2. Seam: S3.
use super::adapter::ProtocolAdapter; use super::fetch::{ParsedResponse, RetrievedRecord}; use crate::ScienceError;
pub fn gene_path(gene_id: &str, max: u32) -> String { format!("/api/v2/reference/gene?geneId={}&itemsPerPage={}", super::url_encode(gene_id), max.clamp(1,25)) }
pub fn parse_search(bytes: &[u8]) -> crate::Result<ParsedResponse> { let v: serde_json::Value = serde_json::from_slice(bytes)?; let genes: Vec<serde_json::Value> = v.get("gene").and_then(|g| g.as_array()).cloned().or_else(|| v.as_array().cloned()).unwrap_or_default(); let mut recs = Vec::with_capacity(genes.len()); for g in &genes { let id = g.get("gencodeId").and_then(|s| s.as_str()).or_else(|| g.get("geneSymbol").and_then(|s| s.as_str())).filter(|s| !s.is_empty()).ok_or_else(|| ScienceError::Invalid("gtex: missing id".into()))?; let name = g.get("geneSymbol").and_then(|s| s.as_str()).unwrap_or(id); recs.push(RetrievedRecord { id: id.to_owned(), title: name.to_owned(), container: "GTEx".to_owned(), url: format!("https://gtexportal.org/home/gene/{id}") }); } Ok(ParsedResponse { total_hits: recs.len() as u64, records: recs }) }
pub struct GtexAdapter;
impl ProtocolAdapter for GtexAdapter { fn descriptor(&self) -> &'static super::ConnectorDescriptor { &super::GTEX } fn expected_exchanges(&self) -> usize { 1 } fn build_fixture_paths(&self, q: &str, m: u32, _f: &[Vec<u8>]) -> crate::Result<Vec<String>> { Ok(vec![gene_path(q, m)]) } fn parse_responses(&self, e: &[super::fetch::FetchExchange]) -> crate::Result<ParsedResponse> { if e.len() != 1 { return Err(ScienceError::Invalid("gtex: 1 exchange".into())); } parse_search(&e[0].response) } }
#[cfg(test)] mod tests { use super::*; const F: &[u8] = br#"{"gene":[{"gencodeId":"ENSG00000139618.15","geneSymbol":"BRCA2"}]}"#; #[test] fn ok() { let p = parse_search(F).unwrap(); assert_eq!(p.total_hits,1); } }
